     1→import React, { useState } from "react";
     2→import { Box, Badge, Group, Text, Collapse, Code } from "@mantine/core";
     3→import type { Event } from "../api";
     4→import { relativeTime } from "./TimeAgo";
     5→
     6→interface Props {
     7→  pre: Event;
     8→  post?: Event;
     9→  failed: boolean;
    10→}
    11→
    12→function str(v: unknown): string { return typeof v === "string" ? v : ""; }
    13→
    14→function toolHint(toolName: string, data: unknown): string {
    15→  if (!data || typeof data !== "object") return "";
    16→  const inp = (data as Record<string, unknown>).tool_input;
    17→  if (!inp || typeof inp !== "object") return "";
    18→  const i = inp as Record<string, unknown>;
    19→  const s = (k: string) => (typeof i[k] === "string" ? String(i[k]) : undefined);
    20→  switch (toolName) {
    21→    case "Read": case "Write": case "Edit": return s("file_path") ?? "";
    22→    case "Bash":      return (s("command") ?? "").replace(/\s+/g, " ").slice(0, 80);
    23→    case "Glob":      return s("pattern") ?? "";
    24→    case "Grep":      return s("pattern") ?? "";
    25→    case "WebFetch":  return s("url") ?? "";
    26→    case "WebSearch": return s("query") ?? "";
    27→    default: return "";
    28→  }
    29→}
    30→
    31→function truncated(val: unknown, max = 1200): string | undefined {
    32→  if (val === undefined) return undefined;
    33→  const s = typeof val === "string" ? val : JSON.stringify(val, null, 2);
    34→  return s.length > max ? s.slice(0, max) + "\n…" : s;
    35→}
    36→
    37→function DiffView({ oldStr, newStr }: { oldStr: string; newStr: string }) {
    38→  return (
    39→    <Box style={{ display: "flex", flexDirection: "column", gap: 4 }}>
    40→      {oldStr && (
    41→        <Box style={{ backgroundColor: "light-dark(var(--mantine-color-red-0), var(--mantine-color-dark-6))", borderLeft: "3px solid var(--mantine-color-red-3)", padding: "4px 6px", borderRadius: 2 }}>
    42→          <Code block style={{ fontSize: 11, lineHeight: "16px", background: "transparent", padding: 0 }}>
    43→            {oldStr.split("\n").map((l) => "− " + l).join("\n")}
    44→          </Code>
    45→        </Box>
    46→      )}
    47→      {newStr && (
    48→        <Box style={{ backgroundColor: "light-dark(var(--mantine-color-green-0), var(--mantine-color-dark-6))", borderLeft: "3px solid var(--mantine-color-green-3)", padding: "4px 6px", borderRadius: 2 }}>
    49→          <Code block style={{ fontSize: 11, lineHeight: "16px", background: "transparent", padding: 0 }}>
    50→            {newStr.split("\n").map((l) => "+ " + l).join("\n")}
    51→          </Code>
    52→        </Box>
    53→      )}
    54→    </Box>
    55→  );
    56→}
    57→
    58→function renderInput(toolName: string, inp: Record<string, unknown>): React.ReactNode {
    59→  switch (toolName) {
    60→    case "Edit": {
    61→      const fp = str(inp.file_path), old = str(inp.old_string), newS = str(inp.new_string);
    62→      return <div>{fp ? <Text size="xs" ff="monospace" c="violet" fw={600} mb={4}>{fp}</Text> : null}<DiffView oldStr={old} newStr={newS} /></div>;
    63→    }
    64→    case "Write": {
    65→      const fp = str(inp.file_path), content = str(inp.content);
    66→      return <div>{fp ? <Text size="xs" ff="monospace" c="violet" fw={600} mb={4}>{fp}</Text> : null}<Code block style={{ fontSize: 11 }}>{content.length > 1200 ? content.slice(0, 1200) + "\n…" : content}</Code></div>;
    67→    }
    68→    case "Read": {
    69→      const fp = str(inp.file_path);
    70→      const extra = (inp.offset != null ? `  offset: ${inp.offset}` : "") + (inp.limit != null ? `  limit: ${inp.limit}` : "");
    71→      return <Text size="xs" ff="monospace" c="violet" fw={600}>{fp}{extra}</Text>;
    72→    }
    73→    case "Bash": return <Code block style={{ fontSize: 11 }}>{str(inp.command)}</Code>;
    74→    case "Glob": case "Grep": {
    75→      const pattern = str(inp.pattern), extra = str(inp.path || inp.glob || inp.type || "");
    76→      return <Code block style={{ fontSize: 11 }}>{pattern}{extra ? "\n" + extra : ""}</Code>;
    77→    }
    78→    case "WebFetch": {
    79→      const url = str(inp.url), prompt = str(inp.prompt);
    80→      return <div><Text size="xs" ff="monospace" c="violet" fw={600} mb={4}>{url}</Text>{prompt ? <Code block style={{ fontSize: 11 }}>{prompt}</Code> : null}</div>;
    81→    }
    82→    case "WebSearch": return <Code block style={{ fontSize: 11 }}>{str(inp.query)}</Code>;
    83→    default: {
    84→      const raw = JSON.stringify(inp, null, 2);
    85→      return <Code block style={{ fontSize: 11 }}>{raw.length > 1200 ? raw.slice(0, 1200) + "\n…" : raw}</Code>;
    86→    }
    87→  }
    88→}
    89→
    90→export function ToolUseItem({ pre, post, failed }: Props) {
    91→  const [expanded, setExpanded] = useState(false);
    92→  const preData = pre.data as Record<string, unknown>;
    93→  const toolName = typeof preData.tool_name === "string" ? preData.tool_name : "?";
    94→  const hint = toolHint(toolName, pre.data);
    95→  const sym = !post ? "▶" : failed ? "✗" : "✓";
    96→  const color = !post ? "blue" : failed ? "red" : "green";
    97→  const toolInput = preData.tool_input as Record<string, unknown> | undefined;
    98→  let outputStr: string | undefined;
    99→  if (post) {
   100→    const postData = post.data as Record<string, unknown>;
   101→    outputStr = failed ? truncated(postData.error) : truncated(postData.tool_response);
   102→  }
   103→  const timeStart = relativeTime(pre.timestamp);
   104→  const timeEnd = post ? relativeTime(post.timestamp) : undefined;
   105→  const showRange = timeEnd && timeEnd !== timeStart;
   106→
   107→  return (
   108→    <Box onClick={() => setExpanded((v) => !v)} style={{ padding: "5px 12px", borderBottom: "1px solid var(--mantine-color-gray-1)", cursor: "pointer" }}>
   109→      <Group gap={6}>
   110→        <Text size="xs" fw={700} c={color} style={{ width: 14, textAlign: "center" }}>{sym}</Text>
   111→        <Text size="xs" fw={600} ff="monospace" c={color} style={{ flexShrink: 0 }}>{toolName}</Text>
   112→        {hint && <Text size="xs" c="dimmed" ff="monospace" style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{hint}</Text>}
   113→        <Text size="xs" c="dimmed" style={{ flexShrink: 0 }}>{timeStart}{showRange ? ` → ${timeEnd}` : ""}</Text>
   114→        {pre.blocked && <Badge color="red" size="xs" variant="filled" fw={700}>BLOCKED</Badge>}
   115→        <Text size="xs" c="dimmed">{expanded ? "▲" : "▼"}</Text>
   116→      </Group>
   117→      <Collapse in={expanded}>
   118→        <Box mt={4} ml={20} mb={4}>
   119→          {toolInput !== undefined && (
   120→            <>
   121→              <Text size="xs" c="dimmed" fw={700} tt="uppercase" style={{ letterSpacing: 0.5, marginTop: 6, marginBottom: 2 }}>input</Text>
   122→              {renderInput(toolName, toolInput)}
   123→            </>
   124→          )}
